/**
 * 3D CYBER-CIRCUIT ENGINE
 * Renders a reactive cyberspace background with glowing PCB traces.
 */
function CircuitBackground() {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext("2d")
    if (!ctx) return

    let width = window.innerWidth
    let height = window.innerHeight
    const gridSize = 45
    let offset = 0
    let mouse = { x: width / 2, y: height / 2 }

    const init = () => {
      width = window.innerWidth
      height = window.innerHeight
      canvas.width = width
      canvas.height = height
    }

    const drawCircuit = () => {
      ctx.clearRect(0, 0, width, height)
      
      // Cyber Dark Base
      ctx.fillStyle = "#020617"
      ctx.fillRect(0, 0, width, height)

      ctx.save()
      // Create 3D Perspective Tilt
      ctx.translate(width / 2, height / 2)
      ctx.rotate(10 * Math.PI / 180) 
      ctx.translate(-width / 2, -height / 2)

      // Grid Traces
      ctx.beginPath()
      ctx.strokeStyle = "rgba(30, 58, 138, 0.3)"
      ctx.lineWidth = 1

      for (let x = -gridSize; x < width + gridSize; x += gridSize) {
        ctx.moveTo(x + (offset % gridSize), 0)
        ctx.lineTo(x + (offset % gridSize), height)
      }
      for (let y = -gridSize; y < height + gridSize; y += gridSize) {
        ctx.moveTo(0, y + (offset % gridSize))
        ctx.lineTo(width, y + (offset % gridSize))
      }
      ctx.stroke()

      // High-Frequency Glowing Trace Nodes
      for (let i = 0; i < 15; i++) {
        const xNode = Math.floor((mouse.x + i * 150) / gridSize) * gridSize
        const yNode = Math.floor((mouse.y - i * 100) / gridSize) * gridSize
        
        ctx.beginPath()
        ctx.shadowBlur = 15
        ctx.shadowColor = "#3b82f6"
        ctx.strokeStyle = "rgba(59, 130, 246, 0.4)"
        ctx.lineWidth = 2
        ctx.moveTo(xNode, yNode)
        ctx.lineTo(xNode + gridSize, yNode)
        ctx.lineTo(xNode + gridSize, yNode + gridSize)
        ctx.stroke()
      }

      ctx.restore()
      
      offset += 0.4
      requestAnimationFrame(drawCircuit)
    }

    const handleMouseMove = (e: MouseEvent) => {
      mouse.x = e.clientX
      mouse.y = e.clientY
    }

    window.addEventListener("resize", init)
    window.addEventListener("mousemove", handleMouseMove)
    init()
    drawCircuit()

    return () => {
      window.removeEventListener("resize", init)
      window.removeEventListener("mousemove", handleMouseMove)
    }
  }, [])

  return (
    <canvas 
      ref={canvasRef} 
      className="absolute inset-0 z-0 opacity-80"
      style={{ filter: "contrast(1.1) brightness(0.9)" }}
    />
  )
}

